ANTAL_GRUPPER = 3

class Grupp:
  def __init__ (self, namn, ständig_medlem):
    self.gruppnamn = namn
    self.medlemmar = [ständig_medlem]

  def __str__ (self):
    sträng = self.gruppnamn + " har följande medlemmar: " 
    for medlem in self.medlemmar:
        sträng += str(medlem +  ", ")
    return sträng[0:-2]

  def lägg_till_medlem(self, ny_medlem):
    self.medlemmar.append(ny_medlem)

  def ta_bort_medlem(self, medlem):
    if medlem in self.medlemmar:
      self.medlemmar.remove(medlem)
      print(medlem, "är borttagen")
    else:
      print("Medlemen finns inte gruppen. ")

  def ordförande(self):
    if len(self.medlemmar) == 0:
      print("Finns inga medlemmar i grupp", self.gruppnamn)
      return None
    ordförande = self.medlemmar[0]
    for i in range(len(self.medlemmar)):
      if len(ordförande) < len(self.medlemmar[i]):
        ordförande = self.medlemmar[i]
    return ordförande

def välj_grupp(grupper):
  grupp_namn = input("Vad heter gruppen? ")
  for grupp in grupper:
    if grupp_namn == grupp.gruppnamn:
      return grupp
  print("Gruppen hittades inte.")

def meny(grupper):
  while True:
    print("Huvudmeny \n1. Visa alla grupper.\
    \n2. Lägga till en medlem i en grupp\
    \n3. Ta bort en medlem\
    \n4. Skriva ut orförande i varje grupp\
    \n5. Avsluta")
    val = input("Vad väljer du?")
    if val == "1":
      for grupp in grupper:
        print(grupp)
    elif val == "2":
      vald_grupp = välj_grupp(grupper)
      if vald_grupp != None:
        medlem = input("Vad heter medlemmen som ska läggas till? ")
        vald_grupp.lägg_till_medlem(medlem)
    elif val == "3":
      vald_grupp = välj_grupp(grupper)
      if vald_grupp != None:
        medlem = input("Vad heter medlemmen som ska tas bort? ")
        vald_grupp.ta_bort_medlem(medlem)
    elif val == "4":
      for grupp in grupper:
        if grupp.ordförande() != None:
          print("Orförande är ", grupp.ordförande())
    elif val =="5":
      print("Programmet avslutas")
      break
    else:
      print("Felaktigt menyval. Försök igen")

def huvudprogram():
  grupper = []
  namn = input("Vad heter den ständiga medlemen? ")
  for i in range(ANTAL_GRUPPER):
    gruppnamn = input("Vad heter grupp " + str(i +1) + "? ")
    grupp = Grupp(gruppnamn, namn)
    grupper.append(grupp)
  meny(grupper)

huvudprogram()
